import jwt
import datetime

def generate_jwt(user_id, role):
    payload = {
        'user_id': user_id,
        'role': role,
        'exp': int(datetime.datetime.utcnow().timestamp()) + 60 * 30  # token expires in 30 minutes
    }
    
    secret_key = 'your_secret_key_here'  # replace with your secret key
    
    return jwt.encode(payload, secret_key, algorithm='HS256')

def verify_jwt(token):
    try:
        payload = jwt.decode(token, 'your_secret_key_here', algorithms=['HS256'])
        return payload
    except Exception as e:
        return str(e)

# Example usage
user_id = 12345
role = 'admin'
jwt_token = generate_jwt(user_id, role)
print(jwt_token)

decoded_token = verify_jwt(jwt_token)
print(decoded_token)